package ru.memearena.scout.infrastructure; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import ru.memearena.scout.domain.*; import java.time.*; import java.util.*; public interface ScoutPointEventRepository extends JpaRepository<ScoutPointEvent,UUID>{ @Query(value="select coalesce(sum(points),0) from scout_point_event where user_id=:u and created_at>=:since",nativeQuery=true) long weeklyPoints(@Param("u") UUID u,@Param("since") Instant since); }
